class DefaultCredentialManager extends CredentialManager {

  override def getCredentialsProvider(credentialType: CredentialType): AwsCredentialsProvider = {
    credentialType match {
      case StaticCredentials(accessKeyId, secretAccessKey) =>
        StaticCredentialsProvider.create(
          AwsBasicCredentials.create(accessKeyId, secretAccessKey)
        )

      case SessionCredentials(accessKeyId, secretAccessKey, sessionToken) =>
        StaticCredentialsProvider.create(
          AwsSessionCredentials.create(accessKeyId, secretAccessKey, sessionToken)
        )

      case ProfileBasedCredentials(profileName) =>
        ProfileCredentialsProvider.create(profileName)

      case DefaultCredentials =>
        DefaultCredentialsProvider.create()

      case AssumeRoleCredentials(roleArn, sessionName) =>
        // This will be handled by assumeRole method
        DefaultCredentialsProvider.create()
    }
  }

  override def assumeRole(roleArn: String, sessionName: String, region: Region): AwsCredentialsProvider = {
    val stsClient = StsClient.builder()
      .region(region)
      .credentialsProvider(DefaultCredentialsProvider.create())
      .build()

    try {
      val assumeRoleRequest = AssumeRoleRequest.builder()
        .roleArn(roleArn)
        .roleSessionName(sessionName)
        .durationSeconds(3600)
        .build()

      val response = stsClient.assumeRole(assumeRoleRequest)
      val credentials = response.credentials()

      StaticCredentialsProvider.create(
        AwsSessionCredentials.create(
          credentials.accessKeyId(),
          credentials.secretAccessKey(),
          credentials.sessionToken()
        )
      )
    } finally {
      stsClient.close()
    }
  }

  override def validateCredentials(provider: AwsCredentialsProvider, region: Region): Try[String] = {
    Try {
      val stsClient = StsClient.builder()
        .region(region)
        .credentialsProvider(provider)
        .build()
      try {
        val identity = stsClient.getCallerIdentity(GetCallerIdentityRequest.builder().build())
        s"Authenticated as: ${identity.arn()}, Account: ${identity.account()}"
      } finally {
        stsClient.close()
      }
    }
  }
}

