class DefaultS3Service(config: AwsConfig, credentialManager: CredentialManager) extends S3Service {

  private val credentialsProvider: AwsCredentialsProvider = config.credentialType match {
    case AssumeRoleCredentials(roleArn, sessionName) =>
      credentialManager.assumeRole(roleArn, sessionName, config.region)
    case other =>
      credentialManager.getCredentialsProvider(other)
  }

  private val s3Client: S3Client = S3Client.builder()
    .region(config.region)
    .credentialsProvider(credentialsProvider)
    .build()

  override def listBuckets(): Try[List[String]] = Try {
    val response = s3Client.listBuckets(ListBucketsRequest.builder().build())
    response.buckets().asScala.map(_.name()).toList
  }

  override def listObjects(bucket: String, prefix: Option[String] = None): Try[List[String]] = Try {
    val requestBuilder = ListObjectsV2Request.builder().bucket(bucket)
    prefix.foreach(p => requestBuilder.prefix(p))
    val response = s3Client.listObjectsV2(requestBuilder.build())
    response.contents().asScala.map(_.key()).toList
  }

  override def putObject(bucket: String, key: String, content: String): Try[String] = Try {
    val request = PutObjectRequest.builder()
      .bucket(bucket)
      .key(key)
      .build()
    val response = s3Client.putObject(request, RequestBody.fromString(content))
    response.eTag()
  }

  override def getObject(bucket: String, key: String): Try[String] = Try {
    val request = GetObjectRequest.builder()
      .bucket(bucket)
      .key(key)
      .build()
    val responseStream = s3Client.getObject(request)
    val content = new String(responseStream.readAllBytes())
    responseStream.close()
    content
  }

  override def deleteObject(bucket: String, key: String): Try[Unit] = Try {
    val request = DeleteObjectRequest.builder()
      .bucket(bucket)
      .key(key)
      .build()
    s3Client.deleteObject(request)
  }

  override def createBucket(bucket: String): Try[String] = Try {
    val request = CreateBucketRequest.builder()
      .bucket(bucket)
      .build()
    val response = s3Client.createBucket(request)
    response.location()
  }

  override def close(): Unit = s3Client.close()
}

