class DefaultDynamoDbService(config: AwsConfig, credentialManager: CredentialManager) extends DynamoDbService {

  private val credentialsProvider: AwsCredentialsProvider = config.credentialType match {
    case AssumeRoleCredentials(roleArn, sessionName) =>
      credentialManager.assumeRole(roleArn, sessionName, config.region)
    case other =>
      credentialManager.getCredentialsProvider(other)
  }

  private val dynamoDbClient: DynamoDbClient = DynamoDbClient.builder()
    .region(config.region)
    .credentialsProvider(credentialsProvider)
    .build()

  private def toAttributeValue(value: String): AttributeValue =
    AttributeValue.builder().s(value).build()

  private def toStringMap(item: java.util.Map[String, AttributeValue]): Map[String, String] =
    item.asScala.map { case (k, v) => k -> v.s() }.toMap

  override def createTable(tableName: String, partitionKey: String): Try[String] = Try {
    val request = CreateTableRequest.builder()
      .tableName(tableName)
      .keySchema(
        KeySchemaElement.builder()
          .attributeName(partitionKey)
          .keyType(KeyType.HASH)
          .build()
      )
      .attributeDefinitions(
        AttributeDefinition.builder()
          .attributeName(partitionKey)
          .attributeType(ScalarAttributeType.S)
          .build()
      )
      .provisionedThroughput(
        ProvisionedThroughput.builder()
          .readCapacityUnits(5L)
          .writeCapacityUnits(5L)
          .build()
      )
      .build()
    val response = dynamoDbClient.createTable(request)
    response.tableDescription().tableArn()
  }

  override def putItem(tableName: String, item: Map[String, String]): Try[Unit] = Try {
    val attributeValues = item.map { case (k, v) => k -> toAttributeValue(v) }.asJava
    val request = PutItemRequest.builder()
      .tableName(tableName)
      .item(attributeValues)
      .build()
    dynamoDbClient.putItem(request)
  }

  override def getItem(tableName: String, key: Map[String, String]): Try[Map[String, String]] = Try {
    val keyAttributes = key.map { case (k, v) => k -> toAttributeValue(v) }.asJava
    val request = GetItemRequest.builder()
      .tableName(tableName)
      .key(keyAttributes)
      .build()
    val response = dynamoDbClient.getItem(request)
    toStringMap(response.item())
  }

  override def scanTable(tableName: String): Try[List[Map[String, String]]] = Try {
    val request = ScanRequest.builder()
      .tableName(tableName)
      .build()
    val response = dynamoDbClient.scan(request)
    response.items().asScala.map(item => toStringMap(item)).toList
  }

  override def deleteItem(tableName: String, key: Map[String, String]): Try[Unit] = Try {
    val keyAttributes = key.map { case (k, v) => k -> toAttributeValue(v) }.asJava
    val request = DeleteItemRequest.builder()
      .tableName(tableName)
      .key(keyAttributes)
      .build()
    dynamoDbClient.deleteItem(request)
  }

  override def close(): Unit = dynamoDbClient.close()
}

