    region = Region.US_EAST_1,
    credentialType = ProfileBasedCredentials("my-profile")
  )

  // Example: Using assume role
  val assumeRoleConfig = AwsConfig(
    region = Region.US_EAST_1,
    credentialType = AssumeRoleCredentials(
      roleArn = "arn:aws:iam::123456789012:role/MyRole",
      sessionName = "my-session"
    )
  )

  // Example: Using session credentials
  val sessionConfig = AwsConfig(
    region = Region.US_EAST_1,
    credentialType = SessionCredentials("ACCESS_KEY", "SECRET_KEY", "SESSION_TOKEN")
  )

  // Validate credentials
  val provider = credentialManager.getCredentialsProvider(defaultConfig.credentialType)
  credentialManager.validateCredentials(provider, defaultConfig.region) match {
    case Success(identity) => println(s"Credential validation successful: $identity")
    case Failure(ex) => println(s"Credential validation failed: ${ex.getMessage}")
  }

  // S3 Operations
  println("=== S3 Operations ===")
  val s3Service = factory.createS3Service(defaultConfig)

  s3Service.listBuckets() match {
    case Success(buckets) => println(s"Buckets: ${buckets.mkString(", ")}")
    case Failure(ex) => println(s"Failed to list buckets: ${ex.getMessage}")
  }

  s3Service.putObject("my-bucket", "test-key", "Hello, AWS!") match {
    case Success(etag) => println(s"Object uploaded with ETag: $etag")
    case Failure(ex) => println(s"Failed to upload object: ${ex.getMessage}")
  }

  s3Service.getObject("my-bucket", "test-key") match {
    case Success(content) => println(s"Object content: $content")
    case Failure(ex) => println(s"Failed to get object: ${ex.getMessage}")
  }

  s3Service.listObjects("my-bucket", Some("test-")) match {
    case Success(objects) => println(s"Objects: ${objects.mkString(", ")}")
    case Failure(ex) => println(s"Failed to list objects: ${ex.getMessage}")
  }

  s3Service.close()

  // SQS Operations
  println("\n=== SQS Operations ===")
  val sqsService = factory.createSqsService(defaultConfig)

  sqsService.createQueue("my-test-queue") match {
    case Success(queueUrl) =>
      println(s"Queue created: $queueUrl")

      sqsService.sendMessage(queueUrl, """{"event": "test", "data": "hello"}""") match {
        case Success(messageId) => println(s"Message sent: $messageId")
        case Failure(ex) => println(s"Failed to send message: ${ex.getMessage}")
      }

      sqsService.receiveMessages(queueUrl, maxMessages = 5, waitTimeSeconds = 2) match {
        case Success(messages) =>
          messages.foreach { case (id, body, receiptHandle) =>
            println(s"Received message $id: $body")
            sqsService.deleteMessage(queueUrl, receiptHandle) match {
              case Success(_) => println(s"Message $id deleted")
              case Failure(ex) => println(s"Failed to delete message: ${ex.getMessage}")
            }
          }
        case Failure(ex) => println(s"Failed to receive messages: ${ex.getMessage}")
      }

    case Failure(ex) => println(s"Failed to create queue: ${ex.getMessage}")
  }

  sqsService.listQueues() match {
    case Success(queues) => println(s"Queues: ${queues.mkString(", ")}")
    case Failure(ex) => println(s"Failed to list queues: ${ex.getMessage}")
  }

  sqsService.close()

  // DynamoDB Operations
  println("\n=== DynamoDB Operations ===")
  val dynamoDbService = factory.createDynamoDbService(defaultConfig)

  dynamoDbService.createTable("my-test-table", "id") match {
    case Success(arn) => println(s"Table created: $arn")
    case Failure(ex) => println(s"Failed to create table (may already exist): ${ex.getMessage}")
  }

  val item = Map(
    "id" -> "user-001",
    "name" -> "John Doe",
    "email" -> "john@example.com",
    "role" -> "admin"
  )

  dynamoDbService.putItem("my-test-table", item) match {
    case Success(_) => println("Item inserted successfully")
    case Failure(ex) => println(s"Failed to insert item: ${ex.getMessage}")
  }

  dynamoDbService.getItem("my-test-table", Map("id" -> "user-001")) match {
    case Success(retrievedItem) =>
      println(s"Retrieved item: ${retrievedItem.mkString(", ")}")
    case Failure(ex) => println(s"Failed to get item: ${ex.getMessage}")
  }

  dynamoDbService.scanTable("my-test-table") match {
    case Success(items) =>
      println(s"Scan results (${items.size} items):")
      items.foreach(item => println(s"  ${item.mkString(", ")}"))
    case Failure(ex) => println(s"Failed to scan table: ${ex.getMessage}")
  }

  dynamoDbService.deleteItem("my-test-table", Map("id" -> "user-001")) match {
    case Success(_) => println("Item deleted successfully")
    case Failure(ex) => println(s"Failed to delete item: ${ex.getMessage}")
  }

  dynamoDbService.close()

  println("\nAll operations completed.")
